const items = $input.all();
const allNews = [];

// دمج كل الأخبار من المصادر المختلفة
for (const item of items) {
  if (item.json.articles) {
    // من GNews API
    for (const article of item.json.articles) {
      allNews.push({
        title: article.title,
        description: article.description || '',
        url: article.url,
        source: article.source.name,
        publishedAt: article.publishedAt,
        image: article.image || ''
      });
    }
  } else if (item.json.items) {
    // من Google RSS
    for (const rssItem of item.json.items) {
      allNews.push({
        title: rssItem.title,
        description: rssItem.description || '',
        url: rssItem.link,
        source: 'Google News',
        publishedAt: rssItem.pubDate,
        image: ''
      });
    }
  }
}

// إزالة المكررات
const uniqueNews = allNews.filter((item, index, self) =>
  index === self.findIndex((t) => t.title === item.title)
);

// ترتيب حسب التاريخ
uniqueNews.sort((a, b) => new Date(b.publishedAt) - new Date(a.publishedAt));

// أخذ أحدث 5 أخبار
const topNews = uniqueNews.slice(0, 5);

return topNews.map(news => ({ json: news }));

