// استخراج النتيجة من Groq API
const response = $input.item.json.choices[0].message.content;

// محاولة parse JSON
let aiResult;
try {
  // إزالة markdown code blocks إن وجدت
  const cleanedResponse = response.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiResult = JSON.parse(cleanedResponse);
} catch (e) {
  // إذا فشل التحليل، استخدم regex للاستخراج
  aiResult = {
    summary: response.substring(0, 200),
    posts: [
      { style: 'default', text: response.substring(0, 280) }
    ],
    hashtags: ['#محرم_بك', '#الإسكندرية'],
    image_suggestion: 'صورة عامة للمنطقة'
  };
}

// دمج البيانات الأصلية مع نتيجة AI
const originalData = $input.item.json;

return {
  json: {
    ...originalData,
    ai_analysis: aiResult,
    processed_at: new Date().toISOString()
  }
};

const item = $input.item.json;
const imageUrl = item.data?.[0]?.url || '';

// إعداد البيانات للحفظ
const posts = item.ai_analysis.posts.map((post, index) => ({
  json: {
    news_title: item.title,
    news_url: item.url,
    news_source: item.source,
    published_at: item.publishedAt,
    post_style: post.style,
    post_text: post.text,
    hashtags: item.ai_analysis.hashtags.join(' '),
    image_url: imageUrl,
    summary: item.ai_analysis.summary,
    status: 'pending_review',
    created_at: new Date().toISOString()
  }
}));

return posts;

